window.__tinePages=[{"favorite":false,"journal":false,"slug":"features-pdf-annotation","title":"Features/PDF annotation"},{"favorite":false,"journal":false,"slug":"features-quick-capture","title":"Features/Quick capture"},{"favorite":false,"journal":false,"slug":"features-tips-shortcuts","title":"Features/Tips & shortcuts"},{"favorite":false,"journal":false,"slug":"project-roadmap","title":"Project/Roadmap"},{"favorite":true,"journal":false,"slug":"welcome-to-tine","title":"Welcome to Tine"}];
window.__tineBlocks=[{"anchor":"b0","slug":"features-pdf-annotation","text":"PDF annotation","title":"Features/PDF annotation"},{"anchor":"b1","slug":"features-pdf-annotation","text":"Open a PDF that lives in your graph's assets/ (or drop one in) and read it in a side pane right next to your notes.","title":"Features/PDF annotation"},{"anchor":"b2","slug":"features-pdf-annotation","text":"Select text in the PDF to highlight it; click a highlight again to change its color.","title":"Features/PDF annotation"},{"anchor":"b3","slug":"features-pdf-annotation","text":"Ctrl+drag a rectangle to clip a figure or an equation as an image highlight.","title":"Features/PDF annotation"},{"anchor":"b4","slug":"features-pdf-annotation","text":"Every highlight becomes a block on a notes page named after the PDF, so you can write underneath it, link it, and reference it like any other bullet — and each note jumps straight back to its spot in the document.","title":"Features/PDF annotation"},{"anchor":"b5","slug":"features-pdf-annotation","text":"It's how you turn a paper into linked, searchable notes without ever leaving Tine.","title":"Features/PDF annotation"},{"anchor":"b0","slug":"features-quick-capture","text":"Global quick-capture","title":"Features/Quick capture"},{"anchor":"b1","slug":"features-quick-capture","text":"A passing thought shouldn't make you switch windows. Bind a desktop shortcut and a small always-on-top capture box pops up over any app — with the full Tine editor — and files what you type straight into your graph. Tine doesn't even need to be focused.","title":"Features/Quick capture"},{"anchor":"b2","slug":"features-quick-capture","text":"What it looks like","title":"Features/Quick capture"},{"anchor":"b3","slug":"features-quick-capture","text":"The quick-capture window — note the optional page-title field at the top","title":"Features/Quick capture"},{"anchor":"b4","slug":"features-quick-capture","text":"Set it up (Linux, one time)","title":"Features/Quick capture"},{"anchor":"b5","slug":"features-quick-capture","text":"Tine listens for a launch with the --capture flag, so bind a global keyboard shortcut in your desktop environment to run tine --capture:","title":"Features/Quick capture"},{"anchor":"b6","slug":"features-quick-capture","text":"GNOME — Settings → Keyboard → View and Customize Shortcuts → Custom Shortcuts → +. Command: tine --capture. Pick a key like Super+N.","title":"Features/Quick capture"},{"anchor":"b7","slug":"features-quick-capture","text":"KDE — System Settings → Shortcuts → Add → Command/URL. Command: tine --capture.","title":"Features/Quick capture"},{"anchor":"b8","slug":"features-quick-capture","text":"Other desktops — add a custom keyboard shortcut that runs tine --capture. Use the binary's full path if it isn't on your PATH.","title":"Features/Quick capture"},{"anchor":"b9","slug":"features-quick-capture","text":"Now press your shortcut from anywhere — the box appears, you type, and it's saved.","title":"Features/Quick capture"},{"anchor":"b10","slug":"features-quick-capture","text":"Where your capture goes","title":"Features/Quick capture"},{"anchor":"b11","slug":"features-quick-capture","text":"Leave the title empty → the text is appended to today's journal. This is the fast path: hotkey, type, done.","title":"Features/Quick capture"},{"anchor":"b12","slug":"features-quick-capture","text":"Type a page title (the field at the top of the window) → it's filed to that page instead, created if it doesn't exist yet. Perfect for \"add this to my Reading notes\" without leaving what you're doing.","title":"Features/Quick capture"},{"anchor":"b13","slug":"features-quick-capture","text":"It's the real editor in there: [[ page links, # tags, / slash commands, and nested bullets all work.","title":"Features/Quick capture"},{"anchor":"b14","slug":"features-quick-capture","text":"Tune the Enter key","title":"Features/Quick capture"},{"anchor":"b15","slug":"features-quick-capture","text":"By default Enter starts a new bullet and Ctrl+Shift+Enter files the capture (so you can jot several lines first). Prefer Enter-to-file? Open Settings and flip Quick-capture: Enter key.","title":"Features/Quick capture"},{"anchor":"b16","slug":"features-quick-capture","text":"The box auto-grows as you type, and it keeps your draft if it loses focus — only Esc or filing it clears the text.","title":"Features/Quick capture"},{"anchor":"b0","slug":"features-tips-shortcuts","text":"Tips & shortcuts","title":"Features/Tips & shortcuts"},{"anchor":"b1","slug":"features-tips-shortcuts","text":"A quick tour of the things that aren't obvious on day one. (Shortcuts are remappable in Settings.)","title":"Features/Tips & shortcuts"},{"anchor":"b2","slug":"features-tips-shortcuts","text":"Find anything — Ctrl+K","title":"Features/Tips & shortcuts"},{"anchor":"b3","slug":"features-tips-shortcuts","text":"Ctrl+K opens the quick switcher: jump to a page, search the text of any block, or run a command — all from one box. Ctrl+Shift+P opens the command palette (commands only).","title":"Features/Tips & shortcuts"},{"anchor":"b4","slug":"features-tips-shortcuts","text":"Slash commands — /","title":"Features/Tips & shortcuts"},{"anchor":"b5","slug":"features-tips-shortcuts","text":"Type / at the start of a bullet for a menu: tasks, headings, a code block, a /calc live calculator, dates (Scheduled / Deadline), callouts, queries, a math block, asset upload, and more.","title":"Features/Tips & shortcuts"},{"anchor":"b6","slug":"features-tips-shortcuts","text":"Tabs","title":"Features/Tips & shortcuts"},{"anchor":"b7","slug":"features-tips-shortcuts","text":"Middle-click any bullet, page, or search result to open it in a background tab. Double-click a tab to pin it, drag to reorder, Ctrl+W to close. Your tabs come back next launch.","title":"Features/Tips & shortcuts"},{"anchor":"b8","slug":"features-tips-shortcuts","text":"The sidebars","title":"Features/Tips & shortcuts"},{"anchor":"b9","slug":"features-tips-shortcuts","text":"t l toggles the left sidebar — journals, favorites, recents, all pages, and a namespace tree. t r toggles the right sidebar; Shift-click any bullet's dot to open it there and keep it beside your work.","title":"Features/Tips & shortcuts"},{"anchor":"b10","slug":"features-tips-shortcuts","text":"Focus mode & dimming — t f / t b","title":"Features/Tips & shortcuts"},{"anchor":"b11","slug":"features-tips-shortcuts","text":"t f (focus mode) hides the sidebars and toolbar so the screen is just your text; layered Esc steps back out.","title":"Features/Tips & shortcuts"},{"anchor":"b12","slug":"features-tips-shortcuts","text":"t b (dim inactive blocks) fades everything except the bullet you're editing — a typewriter-style spotlight. Use it on its own, or let focus mode turn it on for you.","title":"Features/Tips & shortcuts"},{"anchor":"b13","slug":"features-tips-shortcuts","text":"A few more worth knowing","title":"Features/Tips & shortcuts"},{"anchor":"b14","slug":"features-tips-shortcuts","text":"Carry unfinished tasks forward into today (from the command palette) — the last 7 / 30 / 365 days, optionally with their context.","title":"Features/Tips & shortcuts"},{"anchor":"b15","slug":"features-tips-shortcuts","text":"Namespaces: name a page Project/Roadmap and it nests under Project in the sidebar. This page lives under Features.","title":"Features/Tips & shortcuts"},{"anchor":"b16","slug":"features-tips-shortcuts","text":"Page icons: add a property like icon:: 📚 at the very top of a page — that's where the ⌨️ on this one comes from.","title":"Features/Tips & shortcuts"},{"anchor":"b17","slug":"features-tips-shortcuts","text":"Interface zoom with Ctrl + / - / 0, and PDFs, images, and audio all have their own controls.","title":"Features/Tips & shortcuts"},{"anchor":"b0","slug":"project-roadmap","text":"Project / Roadmap","title":"Project/Roadmap"},{"anchor":"b1","slug":"project-roadmap","text":"This page lives in the Project namespace, and it doubles as the target for the reference and the embed over on Welcome to Tine.","title":"Project/Roadmap"},{"anchor":"7a1c0f5e-0000-4000-8000-000000000001","slug":"project-roadmap","text":"Tine round-trips your files byte-for-byte, so you can always switch back to Logseq — nothing here is one-way.","title":"Project/Roadmap"},{"anchor":"b2","slug":"project-roadmap","text":"See the little count badge on the bullet above? That's how many blocks reference it — click the badge to see them.","title":"Project/Roadmap"},{"anchor":"b3","slug":"project-roadmap","text":"A few example tasks","title":"Project/Roadmap"},{"anchor":"b4","slug":"project-roadmap","text":"DOING Write my first real note in Tine","title":"Project/Roadmap"},{"anchor":"b5","slug":"project-roadmap","text":"TODO Set up the quick-capture hotkey — see Features/Quick capture","title":"Project/Roadmap"},{"anchor":"b6","slug":"project-roadmap","text":"TODO Open my own Logseq graph and look around","title":"Project/Roadmap"},{"anchor":"b0","slug":"welcome-to-tine","text":"Welcome to Tine 👋","title":"Welcome to Tine"},{"anchor":"b1","slug":"welcome-to-tine","text":"Tine is a fast, local outliner that reads and writes the same Markdown files as Logseq — the very folder you point it at. Edit here or in Logseq; it's one graph, no import, no export. We have a lot of respect for Logseq — Tine just tries to improve a few things.","title":"Welcome to Tine"},{"anchor":"b2","slug":"welcome-to-tine","text":"Everything you see here is a real Markdown file in this graph's pages/ folder. Open that folder in your file manager and look — nothing is locked away.","title":"Welcome to Tine"},{"anchor":"b3","slug":"welcome-to-tine","text":"Try the basics right now","title":"Welcome to Tine"},{"anchor":"b4","slug":"welcome-to-tine","text":"Click any bullet to edit it. Enter makes a new bullet, Tab indents, Shift+Tab outdents. Drag a bullet's dot to move it (and everything under it).","title":"Welcome to Tine"},{"anchor":"b5","slug":"welcome-to-tine","text":"Tasks — type TODO / DOING / DONE at the start of a bullet, or press Ctrl+Enter to cycle one:","title":"Welcome to Tine"},{"anchor":"b6","slug":"welcome-to-tine","text":"TODO Click this checkbox to complete me","title":"Welcome to Tine"},{"anchor":"b7","slug":"welcome-to-tine","text":"DONE This one is already done","title":"Welcome to Tine"},{"anchor":"b8","slug":"welcome-to-tine","text":"Rich text: bold, italic, ==highlight==, inline code, and even math like $e^{i\\pi} + 1 = 0$.","title":"Welcome to Tine"},{"anchor":"b9","slug":"welcome-to-tine","text":"Links: type ` to link a page or `#` for a #tag. Here's a link to [[Project/Roadmap — click it.","title":"Welcome to Tine"},{"anchor":"b10","slug":"welcome-to-tine","text":"Block references & embeds","title":"Welcome to Tine"},{"anchor":"b11","slug":"welcome-to-tine","text":"Every bullet has a hidden id, so you can point at one specific bullet from anywhere. This is a live reference to a bullet over on the Roadmap:","title":"Welcome to Tine"},{"anchor":"b12","slug":"welcome-to-tine","text":"And here is that same bullet embedded inline — it stays in sync with the original:","title":"Welcome to Tine"},{"anchor":"b13","slug":"welcome-to-tine","text":"{{embed }}","title":"Welcome to Tine"},{"anchor":"b14","slug":"welcome-to-tine","text":"Keep exploring","title":"Welcome to Tine"},{"anchor":"b15","slug":"welcome-to-tine","text":"Features/Quick capture — drop a thought into your graph from any app with a global hotkey. (Set this one up — it's genuinely good.)","title":"Welcome to Tine"},{"anchor":"b16","slug":"welcome-to-tine","text":"Features/Tips & shortcuts — slash commands, the command palette, tabs, the sidebar, focus mode and dimming.","title":"Welcome to Tine"},{"anchor":"b17","slug":"welcome-to-tine","text":"Features/PDF annotation — highlight PDFs and turn them into linked notes.","title":"Welcome to Tine"},{"anchor":"b18","slug":"welcome-to-tine","text":"When you're ready, point Tine at your own Logseq graph: open Settings (t s) and pick a different folder. Your notes stay exactly where they are.","title":"Welcome to Tine"}];
